import numpy as np
from math import ceil, log2, log

def isolation_forest(X: np.ndarray, n_trees: int, sample_size: int, random_state: int = 42) -> np.ndarray:
    """
    Implement Isolation Forest for anomaly detection.

    Parameters:
    - X: 2D numpy array of shape (n_samples, n_features)
    - n_trees: Number of isolation trees to build
    - sample_size: Number of samples to use for building each tree
    - random_state: Random seed for reproducibility

    Returns:
    - scores: 1D numpy array of anomaly scores (higher = more anomalous)
    """
    rng = np.random.RandomState(random_state)
    n_samples, n_features = X.shape
    max_depth = ceil(log2(sample_size)) if sample_size > 1 else 1

    def c(n):
        """Expected average path length for an unsuccessful BST search with n nodes."""
        if n <= 1:
            return 0.0
        if n == 2:
            return 1.0
        # Euler-Mascheroni constant
        return 2.0 * (log(n - 1) + 0.5772156649) - (2.0 * (n - 1) / n)

    def build_tree(data, depth=0):
        """Recursively build an isolation tree node."""
        n = len(data)
        # Terminate at max depth or if only one unique point remains
        if depth >= max_depth or n <= 1:
            return {'type': 'leaf', 'size': n}

        feat = rng.randint(0, n_features)
        min_val = data[:, feat].min()
        max_val = data[:, feat].max()

        # All values identical on this feature — can't split further
        if min_val == max_val:
            return {'type': 'leaf', 'size': n}

        split = rng.uniform(min_val, max_val)
        left_mask = data[:, feat] < split

        return {
            'type': 'node',
            'feature': feat,
            'split': split,
            'left': build_tree(data[left_mask], depth + 1),
            'right': build_tree(data[~left_mask], depth + 1)
        }

    def path_length(x, node, depth=0):
        """Traverse the tree for sample x, returning its estimated path length."""
        if node['type'] == 'leaf':
            # Adjust for the remaining unseen path within the external node
            return depth + c(node['size'])
        if x[node['feature']] < node['split']:
            return path_length(x, node['left'], depth + 1)
        else:
            return path_length(x, node['right'], depth + 1)

    # ---- Build the forest ----
    trees = []
    for _ in range(n_trees):
        indices = rng.choice(n_samples, size=min(sample_size, n_samples), replace=False)
        tree = build_tree(X[indices])
        trees.append(tree)

    # ---- Score every sample ----
    avg_lengths = np.array([
        sum(path_length(x, tree) for tree in trees) / n_trees
        for x in X
    ])

    # Normalize by expected path length for sample_size data points
    norm = c(sample_size)
    if norm == 0:
        return np.full(n_samples, 0.5)

    # s = 2^(-E[h(x)] / c(n)):  close to 1 => anomaly, close to 0.5 => normal
    scores = np.power(2.0, -avg_lengths / norm)
    return scores
